import type { NativeStackScreenProps } from '@react-navigation/native-stack';

export type RootStackParamList = {
  CampaignList: undefined;
  CampaignDetail: { campaignId: string };
  MySubmissions: undefined;
};

export type CampaignListScreenProps = NativeStackScreenProps<RootStackParamList, 'CampaignList'>;
export type CampaignDetailScreenProps = NativeStackScreenProps<
  RootStackParamList,
  'CampaignDetail'
>;
export type MySubmissionsScreenProps = NativeStackScreenProps<RootStackParamList, 'MySubmissions'>;

import { useNavigation } from '@react-navigation/native';
import type { NativeStackNavigationProp } from '@react-navigation/native-stack';
import { FlatList, Pressable, Text, View } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { CAMPAIGNS } from '../data/campaigns';
import { useSubmissions } from '../context/SubmissionsContext';
import type { RootStackParamList } from '../navigation/types';

type Nav = NativeStackNavigationProp<RootStackParamList>;

function formatMoney(n: number) {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(n);
}

export function CampaignListScreen() {
  const navigation = useNavigation<Nav>();
  const { getLatestForCampaign } = useSubmissions();

  return (
    <SafeAreaView className="flex-1 bg-slate-950" edges={['top', 'left', 'right']}>
      <View className="border-b border-slate-800 px-5 pb-4 pt-2">
        <View className="flex-row items-center justify-between">
          <View>
            <Text className="text-xs font-semibold uppercase tracking-widest text-indigo-400">
              Creator
            </Text>
            <Text className="mt-1 text-2xl font-bold text-white">Active campaigns</Text>
            <Text className="mt-1 text-sm text-slate-400">Pick a brief, ship a post, track review.</Text>
          </View>
          <Pressable
            onPress={() => navigation.navigate('MySubmissions')}
            className="rounded-xl bg-slate-800 px-3 py-2 active:opacity-80"
          >
            <Text className="text-xs font-semibold text-indigo-200">My subs</Text>
          </Pressable>
        </View>
      </View>

      <FlatList
        data={CAMPAIGNS}
        keyExtractor={(item) => item.id}
        contentContainerClassName="gap-3 px-5 py-4 pb-8"
        renderItem={({ item }) => {
          const latest = getLatestForCampaign(item.id);
          return (
            <Pressable
              onPress={() => navigation.navigate('CampaignDetail', { campaignId: item.id })}
              className="overflow-hidden rounded-2xl border border-slate-800 bg-slate-900/80 p-4 active:border-indigo-500/60"
            >
              <View className="flex-row items-start justify-between gap-3">
                <View className="min-w-0 flex-1">
                  <Text className="text-lg font-bold text-white">{item.brand}</Text>
                  <Text className="mt-0.5 text-sm text-slate-400" numberOfLines={2}>
                    {item.tagline}
                  </Text>
                </View>
                <View className="items-end">
                  <Text className="text-sm font-semibold text-emerald-400">{formatMoney(item.payoutUsd)}</Text>
                  <Text className="text-[10px] font-medium uppercase tracking-wide text-slate-500">per video</Text>
                </View>
              </View>
              <View className="mt-3 flex-row items-center justify-between border-t border-slate-800/80 pt-3">
                <Text className="text-xs text-slate-500">
                  Deadline <Text className="font-semibold text-slate-300">{item.deadlineLabel}</Text>
                </Text>
                {latest ? (
                  <View
                    className={`rounded-full px-2 py-0.5 ${
                      latest.status === 'approved'
                        ? 'bg-emerald-500/15'
                        : latest.status === 'rejected'
                          ? 'bg-rose-500/15'
                          : 'bg-amber-500/15'
                    }`}
                  >
                    <Text
                      className={`text-[10px] font-bold uppercase tracking-wide ${
                        latest.status === 'approved'
                          ? 'text-emerald-300'
                          : latest.status === 'rejected'
                            ? 'text-rose-300'
                            : 'text-amber-200'
                      }`}
                    >
                      {latest.status}
                    </Text>
                  </View>
                ) : (
                  <Text className="text-[10px] font-semibold uppercase tracking-wide text-slate-600">
                    Not started
                  </Text>
                )}
              </View>
            </Pressable>
          );
        }}
      />
    </SafeAreaView>
  );
}

import { useMemo, useState } from 'react';
import { Alert, Pressable, ScrollView, Text, TextInput, View } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Video, ResizeMode } from 'expo-av';
import type { CampaignDetailScreenProps } from '../navigation/types';
import { getCampaignById } from '../data/campaigns';
import { useSubmissions } from '../context/SubmissionsContext';

function formatMoney(n: number) {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(n);
}

function isLikelyTikTokOrInstagramUrl(raw: string) {
  const u = raw.trim().toLowerCase();
  if (!u.startsWith('http://') && !u.startsWith('https://')) return false;
  try {
    const host = new URL(u).hostname.replace(/^www\./, '');
    return (
      host.includes('tiktok.com') ||
      host.includes('instagram.com') ||
      host.includes('instagr.am')
    );
  } catch {
    return false;
  }
}

function statusBadge(status: 'pending' | 'approved' | 'rejected') {
  if (status === 'approved') return { label: 'Approved', wrap: 'bg-emerald-500/15', text: 'text-emerald-300' };
  if (status === 'rejected') return { label: 'Rejected', wrap: 'bg-rose-500/15', text: 'text-rose-300' };
  return { label: 'Pending review', wrap: 'bg-amber-500/15', text: 'text-amber-200' };
}

export function CampaignDetailScreen({ route, navigation }: CampaignDetailScreenProps) {
  const { campaignId } = route.params;
  const campaign = useMemo(() => getCampaignById(campaignId), [campaignId]);
  const { getLatestForCampaign, submitUrl } = useSubmissions();
  const latest = campaign ? getLatestForCampaign(campaign.id) : undefined;
  const [url, setUrl] = useState('');

  if (!campaign) {
    return (
      <SafeAreaView className="flex-1 items-center justify-center bg-slate-950">
        <Text className="text-slate-400">Campaign not found.</Text>
        <Pressable onPress={() => navigation.goBack()} className="mt-4 rounded-xl bg-indigo-600 px-4 py-3">
          <Text className="font-semibold text-white">Go back</Text>
        </Pressable>
      </SafeAreaView>
    );
  }

  const badge = latest ? statusBadge(latest.status) : null;

  const onSubmit = () => {
    if (!isLikelyTikTokOrInstagramUrl(url)) {
      Alert.alert(
        'Check your link',
        'Paste a full TikTok or Instagram URL (https://…). Mock validation only.',
      );
      return;
    }
    submitUrl(campaign.id, url);
    setUrl('');
    Alert.alert('Submitted', 'Your clip is in the queue. Status updates in a few seconds (mock review).');
  };

  return (
    <SafeAreaView className="flex-1 bg-slate-950" edges={['bottom', 'left', 'right']}>
      <ScrollView className="flex-1" contentContainerClassName="pb-10" keyboardShouldPersistTaps="handled">
        <View className="border-b border-slate-800 px-5 pb-4 pt-2">
          <Pressable onPress={() => navigation.goBack()} hitSlop={12} className="self-start py-1">
            <Text className="text-sm font-semibold text-indigo-400">← Campaigns</Text>
          </Pressable>
          <Text className="mt-2 text-2xl font-bold text-white">{campaign.brand}</Text>
          <Text className="mt-1 text-base text-slate-400">{campaign.tagline}</Text>
          <View className="mt-4 flex-row flex-wrap gap-2">
            <View className="rounded-xl bg-slate-900 px-3 py-2">
              <Text className="text-[10px] font-bold uppercase tracking-wide text-slate-500">Payout</Text>
              <Text className="text-sm font-semibold text-emerald-400">{formatMoney(campaign.payoutUsd)} / video</Text>
            </View>
            <View className="rounded-xl bg-slate-900 px-3 py-2">
              <Text className="text-[10px] font-bold uppercase tracking-wide text-slate-500">Deadline</Text>
              <Text className="text-sm font-semibold text-slate-200">{campaign.deadlineLabel}</Text>
            </View>
            {badge ? (
              <View className={`rounded-xl px-3 py-2 ${badge.wrap}`}>
                <Text className="text-[10px] font-bold uppercase tracking-wide text-slate-400">Your status</Text>
                <Text className={`text-sm font-bold ${badge.text}`}>{badge.label}</Text>
              </View>
            ) : null}
          </View>
        </View>

        <View className="gap-6 px-5 pt-6">
          <View>
            <Text className="text-xs font-bold uppercase tracking-widest text-slate-500">Brief</Text>
            <Text className="mt-2 text-base leading-6 text-slate-200">{campaign.brief}</Text>
          </View>

          <View className="flex-row gap-4">
            <View className="min-w-0 flex-1">
              <Text className="text-xs font-bold uppercase tracking-widest text-emerald-500/90">Do</Text>
              {campaign.dos.map((line) => (
                <Text key={line} className="mt-2 text-sm leading-5 text-slate-300">
                  • {line}
                </Text>
              ))}
            </View>
            <View className="min-w-0 flex-1">
              <Text className="text-xs font-bold uppercase tracking-widest text-rose-500/90">Don&apos;t</Text>
              {campaign.donts.map((line) => (
                <Text key={line} className="mt-2 text-sm leading-5 text-slate-300">
                  • {line}
                </Text>
              ))}
            </View>
          </View>

          <View>
            <Text className="text-xs font-bold uppercase tracking-widest text-slate-500">Example videos</Text>
            <Text className="mt-1 text-sm text-slate-500">Study pacing, framing, and energy — assets are sample MP4s.</Text>
            <View className="mt-4 gap-5">
              {campaign.exampleVideos.map((ex) => (
                <View key={ex.id} className="overflow-hidden rounded-2xl border border-slate-800 bg-black">
                  <Text className="border-b border-slate-800 bg-slate-900 px-3 py-2 text-xs font-semibold text-slate-300">
                    {ex.title}
                  </Text>
                  <Video
                    source={{ uri: ex.uri }}
                    style={{ width: '100%', height: 220 }}
                    useNativeControls
                    resizeMode={ResizeMode.CONTAIN}
                    isLooping={false}
                  />
                </View>
              ))}
            </View>
          </View>

          <View className="rounded-2xl border border-slate-800 bg-slate-900/60 p-4">
            <Text className="text-xs font-bold uppercase tracking-widest text-indigo-300">Submit post URL</Text>
            <Text className="mt-1 text-sm text-slate-500">TikTok or Instagram public link to your published video.</Text>
            <TextInput
              value={url}
              onChangeText={setUrl}
              placeholder="https://www.tiktok.com/@you/video/…"
              placeholderTextColor="#64748b"
              autoCapitalize="none"
              autoCorrect={false}
              keyboardType="url"
              className="mt-3 rounded-xl border border-slate-700 bg-slate-950 px-3 py-3 text-base text-white"
            />
            <Pressable
              onPress={onSubmit}
              className="mt-3 items-center rounded-xl bg-indigo-600 py-3.5 active:opacity-90"
            >
              <Text className="text-base font-bold text-white">Submit for review</Text>
            </Pressable>
            {latest ? (
              <View className="mt-4 border-t border-slate-800 pt-4">
                <Text className="text-xs font-bold uppercase tracking-widest text-slate-500">Latest submission</Text>
                <Text className="mt-2 text-xs text-slate-500">URL</Text>
                <Text selectable className="text-sm text-indigo-200">
                  {latest.videoUrl}
                </Text>
                <Text className="mt-3 text-xs text-slate-500">Status</Text>
                <Text className={`text-sm font-bold ${statusBadge(latest.status).text}`}>
                  {statusBadge(latest.status).label}
                </Text>
              </View>
            ) : null}
          </View>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

import { FlatList, Pressable, Text, View } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import type { MySubmissionsScreenProps } from '../navigation/types';
import { CAMPAIGNS, getCampaignById } from '../data/campaigns';
import { useSubmissions } from '../context/SubmissionsContext';

function statusStyle(status: 'pending' | 'approved' | 'rejected') {
  if (status === 'approved') return { wrap: 'bg-emerald-500/15', text: 'text-emerald-300' };
  if (status === 'rejected') return { wrap: 'bg-rose-500/15', text: 'text-rose-300' };
  return { wrap: 'bg-amber-500/15', text: 'text-amber-200' };
}

export function MySubmissionsScreen({ navigation }: MySubmissionsScreenProps) {
  const { submissions } = useSubmissions();

  return (
    <SafeAreaView className="flex-1 bg-slate-950" edges={['top', 'left', 'right']}>
      <View className="border-b border-slate-800 px-5 pb-4 pt-2">
        <Pressable onPress={() => navigation.goBack()} hitSlop={12} className="self-start py-1">
          <Text className="text-sm font-semibold text-indigo-400">← Back</Text>
        </Pressable>
        <Text className="mt-2 text-2xl font-bold text-white">My submissions</Text>
        <Text className="mt-1 text-sm text-slate-400">Newest first. Mock reviewer resolves after a short delay.</Text>
      </View>

      <FlatList
        data={submissions}
        keyExtractor={(item) => item.id}
        ListEmptyComponent={
          <View className="mx-5 mt-10 rounded-2xl border border-dashed border-slate-700 bg-slate-900/40 p-6">
            <Text className="text-center text-base text-slate-300">No submissions yet.</Text>
            <Text className="mt-2 text-center text-sm text-slate-500">
              Open a campaign, watch the examples, then paste your TikTok or Instagram URL.
