import { useEffect, useState } from 'react';
import { Platform, Text, View, useWindowDimensions } from 'react-native';
import { Audio, Video, ResizeMode } from 'expo-av';

type Props = {
  title: string;
  uri: string;
};

let audioModeReady = false;

async function ensurePlaybackAudioMode() {
  if (audioModeReady) return;
  try {
    await Audio.setAudioModeAsync({
      playsInSilentModeIOS: true,
      staysActiveInBackground: false,
      shouldDuckAndroid: true,
      playThroughEarpieceAndroid: false,
    });
    audioModeReady = true;
  } catch {
    /* ignore — video may still play muted */
  }
}

export function ExampleVideoCard({ title, uri }: Props) {
  const { width } = useWindowDimensions();
  const videoWidth = Math.max(0, width - 40);
  const height = 220;
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    void ensurePlaybackAudioMode();
  }, []);

  return (
    <View className="rounded-2xl border border-slate-800 bg-black">
      <View className="rounded-t-2xl border-b border-slate-800 bg-slate-900 px-3 py-2">
        <Text className="text-xs font-semibold text-slate-300">{title}</Text>
      </View>
      {/* Android: avoid overflow:hidden clipping SurfaceView; collapsable={false} keeps native view in hierarchy */}
      <View
        collapsable={false}
        style={{
          width: videoWidth,
          height,
          alignSelf: 'center',
          backgroundColor: '#000',
        }}
        {...(Platform.OS === 'android' ? { renderToHardwareTextureAndroid: true } : {})}
      >
        <Video
          source={{ uri }}
          style={{ width: videoWidth, height }}
          useNativeControls
          resizeMode={ResizeMode.CONTAIN}
          isLooping={false}
          shouldPlay={false}
          isMuted={false}
          volume={1}
          onError={(msg) => setError(msg)}
        />
      </View>
      {error ? (
        <Text className="border-t border-slate-800 bg-rose-950/40 px-3 py-2 text-xs text-rose-300">
          Could not load video: {error}
        </Text>
      ) : null}
    </View>
  );
}

